mapper.select:
SELECT BOARD_NO, BOARD_TITLE, WRITER_COMPANY, BOARD_WRITE_DATE, BOARD_VIEW_COUNT, BOARD_CATEGORY FROM "BOARD" WHERE BOARD_DEL_FL = 'N' AND BOARD_TYPE_CODE = #{boardTypeCode}
ORDER BY BOARD_VIEW_COUNT DESC, BOARD_NO DESC
ORDER BY BOARD_WRITE_DATE DESC, BOARD_NO DESC

mapper.update:
UPDATE "BOARD" SET
BOARD_VIEW_COUNT = BOARD_VIEW_COUNT + 1
WHERE BOARD_NO = #{boardNo}
